func (t *onceMore) Do(f func()) {
	if atomic.LoadUint32(&t.done) == 1 {
		return
	}

	locked := atomic.CompareAndSwapUint32(&t.lock, 0, 1)
	if !locked {
		return
	}
	defer atomic.StoreUint32(&t.lock, 0)

	t.mu.Lock()
	defer t.mu.Unlock()

	if t.done == 1 {
		return
	}
	defer atomic.StoreUint32(&t.done, 1)
	f()
}
